
SET XACT_ABORT ON;

BEGIN TRY
    BEGIN TRANSACTION;

    -- If RDB_DATE is completely empty, add the special NULL/default row first.
    IF (SELECT COUNT_BIG(*) FROM [dbo].[RDB_DATE]) = 0
    BEGIN
    END;

    -- If the only row is the special NULL/default row, load the remaining calendar dates.
    IF (SELECT COUNT_BIG(*) FROM [dbo].[RDB_DATE]) = 1
       AND EXISTS (
            SELECT 1
            FROM [dbo].[RDB_DATE]
            WHERE [DATE_KEY] = 1
              AND [DATE_MM_DD_YYYY] IS NULL
       )
    BEGIN
        -- Rows 1 through 1000 of 14975 non-NULL date rows

        -- Rows 1001 through 2000 of 14975 non-NULL date rows

        -- Rows 2001 through 3000 of 14975 non-NULL date rows

        -- Rows 3001 through 4000 of 14975 non-NULL date rows

        -- Rows 4001 through 5000 of 14975 non-NULL date rows

        -- Rows 5001 through 6000 of 14975 non-NULL date rows

        -- Rows 6001 through 7000 of 14975 non-NULL date rows

        -- Rows 7001 through 8000 of 14975 non-NULL date rows

        -- Rows 8001 through 9000 of 14975 non-NULL date rows

        -- Rows 9001 through 10000 of 14975 non-NULL date rows

        -- Rows 10001 through 11000 of 14975 non-NULL date rows

        -- Rows 11001 through 12000 of 14975 non-NULL date rows

        -- Rows 12001 through 13000 of 14975 non-NULL date rows

        -- Rows 13001 through 14000 of 14975 non-NULL date rows

        -- Rows 14001 through 14975 of 14975 non-NULL date rows

    END
    ELSE IF (SELECT COUNT_BIG(*) FROM [dbo].[RDB_DATE]) > 1
    BEGIN
        PRINT 'RDB_DATE already has more than the NULL/default row. No calendar rows were inserted.';
    END;

    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;

    THROW;
END CATCH;
